import{e}from"./index-Dojqw-ZK.js";const s={getAllUnits:async()=>{try{console.log("Fetching all units");const r=await e.get("/units");return console.log("Units API response:",r),r}catch(r){throw console.error("Error fetching all units:",r),r}},getUnitsGrouped:async()=>{try{return await e.get("/units/grouped")}catch(r){throw console.error("Error fetching grouped units:",r),r}},getBasicUnits:async()=>{try{console.log("Fetching basic units");const r=await e.get("/units/basic");return console.log("Basic units API response:",r),r}catch(r){throw console.error("Error fetching basic units:",r),r}},getUnitsByBasicType:async r=>{try{return await e.get(`/units/type/${r}`)}catch(t){throw console.error("Error fetching units by basic type:",t),t}},getMultiUnits:async r=>{try{return await e.get(`/units/multi/${r}`)}catch(t){throw console.error("Error fetching multi units:",t),t}},getCompatibleUnits:async r=>{try{return r?e.get(`/units/compatible/${r}`):e.get("/units/basic")}catch(t){throw console.error("Error fetching compatible units:",t),t}},getShowingUnits:async()=>{try{console.log("Fetching showing units");const r=await e.get("/units/show");return console.log("Showing units API response:",r),r}catch(r){throw console.error("Error fetching showing units:",r),r}},getUnitById:async r=>{try{return await e.get(`/units/${r}`)}catch(t){throw console.error("Error fetching unit by ID:",t),t}},addUnit:async r=>{try{return console.log("Adding new unit:",r),await e.post("/units",r)}catch(t){throw console.error("Error adding unit:",t),t}},updateUnit:async(r,t)=>{try{return console.log(`Updating unit ${r}:`,t),await e.put(`/units/${r}`,t)}catch(o){throw console.error("Error updating unit:",o),o}},updateStatus:async(r,t)=>{try{return await e.put(`/units/status/${r}`,{status:t})}catch(o){throw console.error("Error updating unit status:",o),o}},deleteUnit:async r=>{try{return await e.delete(`/units/${r}`)}catch(t){throw console.error("Error deleting unit:",t),t}}};export{s as U};
